<div class="en">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Dispute Resolution Time Compared (illustrative order, not linear)</text>
  <g font-family="sans-serif">
    <text x="20" y="72" fill="#d4d4d8" font-size="14">Traditional litigation</text>
    <rect x="220" y="58" width="430" height="26" rx="4" fill="#52525b"/>
    <text x="640" y="76" fill="#f2f2f5" font-size="13" text-anchor="end" font-weight="700">Months to years</text>
    <text x="20" y="132" fill="#d4d4d8" font-size="14">Commercial arbitration (ICC)</text>
    <rect x="220" y="118" width="340" height="26" rx="4" fill="#71717a"/>
    <text x="550" y="136" fill="#f2f2f5" font-size="13" text-anchor="end" font-weight="700">Weeks to months</text>
    <text x="20" y="192" fill="#d4d4d8" font-size="14">Kleros</text>
    <rect x="220" y="178" width="230" height="26" rx="4" fill="#a1a1aa"/>
